PROCEDURE SyncWithTimeServer(serverAddress)
 // Record send time
 T1 ← currentLocalTime()

 // Send request to time server
 send(REQUEST, serverAddress)

 // Wait for response
 response ← receive()

 // Record receive time
 T4 ← currentLocalTime()

 // Extract server timestamps
 T2 ← response.serverReceiveTime // When server got request
 T3 ← response.serverSendTime // When server sent response

 // Calculate round-trip time
 RTT ← T4 - T1

 // Estimate one-way delay (assuming symmetric)
 oneWayDelay ← RTT / 2

 // Estimate correct time
 estimatedCorrectTime ← T3 + oneWayDelay

 // Calculate offset
 offset ← estimatedCorrectTime - currentLocalTime()

 // Adjust local clock
 adjustClock(offset)

 // Return synchronization info
 RETURN {offset, RTT, accuracy: oneWayDelay}
END PROCEDURE

PROCEDURE NTPSync(serverAddress)
 // Step 1: Create NTP packet
 packet ← new NTPPacket()
 packet.transmitTimestamp ← currentLocalTime()

 // Step 2: Send request, record T1
 T1 ← currentLocalTime()
 send(packet, serverAddress)

 // Step 3: Receive response
 responsePacket ← receive()
 T4 ← currentLocalTime()

 // Extract server timestamps
 T2 ← responsePacket.receiveTimestamp // Server received
 T3 ← responsePacket.transmitTimestamp // Server sent

 // Step 4: Calculate offset and delay
 // Offset: mean of two offset estimates
 offset1 ← T2 - T1
 offset2 ← T3 - T4
 offset ← (offset1 + offset2) / 2

 // Round-trip delay
 delay ← (T4 - T1) - (T3 - T2)

 // Step 5: Adjust local clock
 adjustClock(offset)

 RETURN {offset, delay, stratum: responsePacket.stratum}
END PROCEDURE

// NTP also supports symmetric mode with 4 messages
// and uses multiple servers for better accuracy
PROCEDURE MultiServerNTP(serverList)
 results ← []
 FOR EACH server IN serverList DO
 result ← NTPSync(server)
 results.append(result)
 END FOR

 // Select best candidates using clustering algorithm
 selected ← selectBestServers(results)

 // Compute final offset from selected servers
 finalOffset ← computeWeightedAverage(selected)

 adjustClock(finalOffset)
END PROCEDURE
